from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not search_results or not filter_specs:
        return search_results

    # Convert SearchResult objects to dictionaries for filtering
    result_dicts = []
    result_mapping = {}

    for idx, result in enumerate(search_results):
        # Convert SearchResult to dictionary format
        # Assuming SearchResult has a to_dict() method or similar interface
        if hasattr(result, 'to_dict'):
            result_dict = result.to_dict()
        else:
            # Fallback: extract metadata from SearchResult object
            result_dict = {
                'id': getattr(result, 'id', idx),
                'metadata': getattr(result, 'metadata', {}),
                'score': getattr(result, 'score', 0.0),
                'content': getattr(result, 'content', '')
            }

        result_dicts.append(result_dict)
        result_mapping[idx] = result

    # Initialize MetadataFilterEngine
    filter_engine = MetadataFilterEngine()

    # Configure filter logic
    if filter_logic.upper() == "AND":
        filter_engine.set_logic_and()
    else:  # OR logic
        filter_engine.set_logic_or()

    # Add filter specifications to the engine
    for field_name, filter_conditions in filter_specs.items():
        for operator, value in filter_conditions.items():
            filter_engine.add_filter(field_name, operator, value)

    # Apply filters to the dictionary representations
    filtered_dicts = filter_engine.apply_filters(result_dicts)

    # Map filtered dictionaries back to original SearchResult objects
    filtered_results = []

    for filtered_dict in filtered_dicts:
        # Find the original result that matches this filtered dictionary
        for idx, original_dict in enumerate(result_dicts):
            if self._dicts_match(original_dict, filtered_dict):
                filtered_results.append(result_mapping[idx])
                break

    return filtered_results

def _dicts_match(self, dict1: Dict, dict2: Dict) -> bool:
    """Check if two dictionaries represent the same result."""
    # Compare based on unique identifier if available
    if 'id' in dict1 and 'id' in dict2:
        return dict1['id'] == dict2['id']

    # Fallback: compare all fields
    return all(
        dict1.get(key) == dict2.get(key) 
        for key in set(dict1.keys()) | set(dict2.keys())
        if not key.startswith('_')  # Skip internal fields
    )

