    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Group results by the specified metadata field
    grouped_results = defaultdict(list)

    for result in search_results:
        # Get the grouping field value, handle missing values as 'unknown'
        group_value = getattr(result, group_by_field, None)
        if group_value is None:
            # Try to get from metadata if available
            if hasattr(result, 'metadata') and group_by_field in result.metadata:
                group_value = result.metadata[group_by_field]
            else:
                group_value = 'unknown'

        grouped_results[group_value].append(result)

    # Define default aggregation functions if none provided
    if aggregation_funcs is None:
        aggregation_funcs = {
            'count': lambda results: len(results),
            'avg_score': lambda results: sum(r.score for r in results) / len(results) if results else 0,
            'max_score': lambda results: max(r.score for r in results) if results else 0,
            'min_score': lambda results: min(r.score for r in results) if results else 0
        }

    # Calculate statistics for each group
    aggregated_stats = {}

    for group_value, results in grouped_results.items():
        group_stats = {}

        # Apply each aggregation function to the group's results
        for stat_name, agg_func in aggregation_funcs.items():
            try:
                group_stats[stat_name] = agg_func(results)
            except Exception as e:
                # Handle potential errors in aggregation functions
                group_stats[stat_name] = None
                print(f"Warning: Error calculating {stat_name} for group {group_value}: {e}")

        aggregated_stats[group_value] = group_stats

    return aggregated_stats

